// // This module is designed to capture and store two separate input signals (a and b) on the falling edge of a clock signal (clk), and outputs the stored values on q and q1, respectively.
module top_module( a,b,c, clk, q,q1,q2);input a,b,c,clk;
   output q, q1,q2;
   wire clk;
   reg q, q1,q2;

   always @ (posedge clk)
   begin
    q <= a;
    q1<=b;
    q2 <= c;
 end

endmodule
